import akka.actor._
import akka.http.scaladsl.Http;
import akka.stream.scaladsl.{Flow, Sink, Source}
import scala.util.{Success, Failure}

object WebhookProxyService {
  case class Request(url: String)
  
  def main(args: Array[String]): Unit = {
    val system = ActorSystem("WebhookProxy")
    
    implicit val executionContext = system.dispatcher
      
      // Create a flow that reads the URL from POST body, then fetches content and sends it back to client 
        Source(Request(args(0))).via(proxyFlow) ! "http://example/api" map { request =>  
          Http().singleRequest(HttpRequest(uri = request.url)).toCompletableFuture() match{
            case Success((response, _)) =>  response // return the content as is 
            | Failure(_)              => throw new Exception("Failed to fetch url")   
        }  
      }) !> Sink.foreach(println)(_.entityAsString())    
      
          system.terminate()        
}